import { useExtensions, TypedGuestConnection } from '@adobe/uix-host-react'
import { useMemo } from 'react'
import { GuestApis } from '@adobe/uix-core'
import { UixFrame, updatePageTitle } from './utils'
import { OrderViewButtonPageProps } from './props/OrderViewButtonProps'

export const OrderViewButtonPage = ({
  extensionId,
  orderId,
  redirectUrl,
  buttonPath,
  pageTitle
}: OrderViewButtonPageProps) => {
  const orderIdParam = 'orderId'

  const { extensions } = useExtensions(() => ({
    updateOn: 'all',
    provides: {
      integration: {
        getCommerceHost() {
          return window.location.host
        }
      }
    }
  }))

  const extension: TypedGuestConnection<GuestApis> | null = useMemo(
    () => extensions.find((item) => item.id === extensionId) ?? null,
    [extensions, extensionId]
  )

  if (!extension) {
    return <></>
  } else {
    updatePageTitle(pageTitle)
  }

  return (
    <UixFrame
      url={`${extension.url.origin}/index.html${buttonPath}?${orderIdParam}=${orderId}`}
      extensionId={extension?.id}
      redirectUrl={redirectUrl}
    />
  )
}
