import React from 'react'
import ReactDOM from 'react-dom/client'
import { OrderViewButtonPage } from '../components/page/OrderViewButtonPage'
import { Extensible } from '../components/extensible/Extensible'
import { UixContainer } from '../components/page/UixContainer'

export const displayOrderViewButtons = (
  config,
  selectedExtension,
  imsToken
) => {
  const sharedContext = {
    imsToken: imsToken
  }

  const contentElement = ReactDOM.createRoot(
    document.getElementById('uix-order-view-button')
  )

  contentElement.render(
    <React.StrictMode>
      <UixContainer>
        <Extensible
          extensions={selectedExtension}
          sharedContext={sharedContext}
        >
          <OrderViewButtonPage
            extensionId={Object.keys(selectedExtension)[0] ?? ''}
            orderId={config.orderViewButton.orderId}
            redirectUrl={config.orderViewButton.redirectUrl}
            buttonPath={config.orderViewButton.buttonPath}
            pageTitle={config.orderViewButton.pageTitle}
          />
        </Extensible>
      </UixContainer>
    </React.StrictMode>
  )
}
