import React from 'react'
import ReactDOM from 'react-dom/client'
import { MenuPage } from '../components/page/MenuPage'
import { Extensible } from '../components/extensible/Extensible'
import { UixContainer } from '../components/page/UixContainer'

export const displayMenuPage = (selectedExtension, imsToken) => {
  const sharedContext = {
    imsToken: imsToken
  }

  const contentElement = ReactDOM.createRoot(
    document.getElementById('uix-page-content')
  )
  contentElement.render(
    <React.StrictMode>
      <UixContainer>
        <Extensible
          extensions={selectedExtension}
          sharedContext={sharedContext}
        >
          <MenuPage extensionId={Object.keys(selectedExtension)[0] ?? ''} />
        </Extensible>
      </UixContainer>
    </React.StrictMode>
  )
}
