import React from 'react'
import ReactDOM from 'react-dom/client'
import { Extensible } from '../components/extensible/Extensible'
import { MassActionPage } from '../components/page/MassActionPage'
import { UixContainer } from '../components/page/UixContainer'

export const displayMassAction = (
  config,
  imsToken,
  selectedIds,
  selectedExtension
) => {
  const sharedContext = {
    selectedIds: selectedIds,
    commerceBaseUrl: config.commerce.baseUrl,
    imsToken: imsToken,
    clientId: config.commerce.clientId
  }

  const contentElement = ReactDOM.createRoot(
    document.getElementById('uix-mass-action')
  )
  contentElement.render(
    <React.StrictMode>
      <UixContainer>
        <Extensible
          sharedContext={sharedContext}
          extensions={selectedExtension}
        >
          <MassActionPage
            extensionId={Object.keys(selectedExtension)[0] ?? ''}
            redirectUrl={config.massAction.redirectUrl}
            actionUrlPath={config.massAction.actionUrlPath}
            pageTitle={config.massAction.pageTitle}
          />
        </Extensible>
      </UixContainer>
    </React.StrictMode>
  )
}
